mapper.select:
SELECT seq as seq ,division ,army_name AS armyName ,DATE_FORMAT(created_at, '%Y-%m-%d %H:%i') AS createdAt ,DATE_FORMAT(updated_at, '%Y-%m-%d %H:%i') AS updatedAt ,( SELECT count(tid.division) FROM tb_cs_info_division tid
